    print(f"  (column={gen_result.column_pairs}, "
          f"fk={gen_result.fk_pairs}, "
          f"value={gen_result.value_pairs}, "
          f"fallback={gen_result.fallback_pairs})")
    print()

    print("Running auto fine-tuning...\n")
    result = run_auto_finetune(
        inference_result = inference_result,
        verbose          = True,
    )

    print("=" * 70)
    print("VEDA POC — Auto Fine-Tune Output")
    print("=" * 70)
    if result.skipped:
        print(f"  Skipped           : {result.skip_reason}")
    else:
        print(f"  Success           : {result.success}")
        print(f"  Pairs used        : {result.pairs_used}")
        print(f"  Epochs completed  : {result.epochs_completed}")
        print(f"  Checkpoint        : {result.checkpoint_path}")
        print(f"  Duration          : {result.duration_sec}s")
        print()
        meta = get_checkpoint_meta()
        if meta:
            print(f"  Checkpoint meta   :")
            for k, v in meta.items():
                print(f"    {k:<20} : {v}")